"use client";

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Search, Package, Truck, CheckCircle, Clock, MapPin, Phone, Mail, ArrowLeft } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import Link from 'next/link';
import Image from 'next/image';
import { toast } from 'sonner';

interface TrackingHistory {
  status: string;
  timestamp: string;
  description: string;
}

interface TrackingInfo {
  id: string;
  trackingNumber: string;
  status: string;
  estimatedDelivery?: string;
  createdAt: string;
  updatedAt: string;
  trackingHistory: TrackingHistory[];
  shippingAddress: {
    city: string;
    state: string;
    pincode: string;
  };
  items?: Array<{
    id: string;
    name: string;
    quantity: number;
    price: number;
    image?: string;
  }>;
}

const TrackOrderPage = () => {  const [trackingNumber, setTrackingNumber] = useState('');
  const [trackingInfo, setTrackingInfo] = useState<TrackingInfo | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  // Get tracking number from URL if provided
  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const orderId = urlParams.get('orderId');
    if (orderId) {
      setTrackingNumber(orderId);
      handleTrackOrder(orderId);
    }
  }, []);
  const handleTrackOrder = async (tracking?: string) => {
    const trackingNum = tracking || trackingNumber;
    
    if (!trackingNum.trim()) {
      setError('Please enter a tracking number');
      return;
    }

    setLoading(true);
    setError(null);
    setTrackingInfo(null);
    
    try {
      // Create mock data since we don't have a real server API yet
      const mockTrackingData = getMockTrackingData(trackingNum);
      
      if (!mockTrackingData) {
        throw new Error('Order not found with this tracking number');
      }
      
      // Short delay to simulate API call      await new Promise(resolve => setTimeout(resolve, 1000));
      
      setTrackingInfo(mockTrackingData);
      toast.success(`Order found! Status: ${mockTrackingData.status}`);

    } catch (error: any) {
      setError(error.message || 'Failed to track order. Please check your tracking number.');
      toast.error(error.message || 'Please check your tracking number and try again.');
    } finally {
      setLoading(false);
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status.toLowerCase()) {
      case 'order placed':
      case 'received':
        return <Clock className="h-5 w-5" />;
      case 'order confirmed':
      case 'processing':
        return <Package className="h-5 w-5" />;
      case 'shipped':
      case 'out for delivery':
        return <Truck className="h-5 w-5" />;
      case 'delivered':
        return <CheckCircle className="h-5 w-5" />;
      default:
        return <Clock className="h-5 w-5" />;
    }
  };

  const getStatusColor = (status: string) => {
    switch (status.toLowerCase()) {
      case 'delivered':
        return 'bg-green-100 text-green-800 border-green-200';
      case 'shipped':
      case 'out for delivery':
        return 'bg-blue-100 text-blue-800 border-blue-200';
      case 'processing':
        return 'bg-yellow-100 text-yellow-800 border-yellow-200';
      case 'cancelled':
        return 'bg-red-100 text-red-800 border-red-200';
      default:
        return 'bg-gray-100 text-gray-800 border-gray-200';
    }
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleString('en-IN', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  // Mock function to generate tracking data
  const getMockTrackingData = (trackingNum: string): TrackingInfo | null => {
    // Demo tracking numbers (plus any order ID passed from order confirmation)
    const validTrackingNumbers = ['TRK001425', 'TRK001426', 'TRK001427'];
    
    // If it's a valid tracking number or starts with "KT" (from order confirmation)
    if (validTrackingNumbers.includes(trackingNum) || trackingNum.startsWith('KT')) {
      const now = new Date();
      const createdAt = new Date(now.getTime() - 1000 * 60 * 60 * 3); // 3 hours ago
      const updatedAt = new Date(now.getTime() - 1000 * 60 * 30); // 30 mins ago
      const estimatedDelivery = new Date(now.getTime() + 1000 * 60 * 60 * 24); // 24 hours from now
      
      // Randomly select a status based on the tracking number
      const statuses = ['order placed', 'processing', 'shipped', 'out for delivery', 'delivered'];
      const statusIndex = (trackingNum.charCodeAt(trackingNum.length - 1) % 5);
      const currentStatus = statuses[statusIndex];
      
      // Generate tracking history based on status
      const trackingHistory: TrackingHistory[] = [];
      
      // Always add "order placed"
      trackingHistory.push({
        status: 'Order Placed',
        timestamp: new Date(createdAt).toISOString(),
        description: 'Your order has been received and is being processed'
      });
      
      // Add "processing" if status is beyond that
      if (statusIndex >= 1) {
        trackingHistory.push({
          status: 'Processing',
          timestamp: new Date(createdAt.getTime() + 1000 * 60 * 60).toISOString(),
          description: 'Your order is being prepared for shipment'
        });
      }
      
      // Add "shipped" if status is beyond that
      if (statusIndex >= 2) {
        trackingHistory.push({
          status: 'Shipped',
          timestamp: new Date(createdAt.getTime() + 1000 * 60 * 60 * 2).toISOString(),
          description: 'Your order has been shipped and is on its way'
        });
      }
      
      // Add "out for delivery" if status is beyond that
      if (statusIndex >= 3) {
        trackingHistory.push({
          status: 'Out for Delivery',
          timestamp: new Date(updatedAt).toISOString(),
          description: 'Your order is out for delivery and will arrive soon'
        });
      }
      
      // Add "delivered" if status is delivered
      if (statusIndex === 4) {
        trackingHistory.push({
          status: 'Delivered',
          timestamp: new Date().toISOString(),
          description: 'Your order has been delivered successfully'
        });
      }
      
      // Sample items
      const items = [
        {
          id: '1',
          name: 'Fresh Seer Fish (Large)',
          quantity: 2,
          price: 799,
          image: '/images/products/seer-fish.jpg'
        },
        {
          id: '2',
          name: 'Tiger Prawns (500g)',
          quantity: 1,
          price: 599,
          image: '/images/products/tiger-prawns.jpg'
        }
      ];
      
      return {
        id: trackingNum,
        trackingNumber: trackingNum,
        status: currentStatus,
        estimatedDelivery: estimatedDelivery.toISOString(),
        createdAt: createdAt.toISOString(),
        updatedAt: updatedAt.toISOString(),
        shippingAddress: {
          city: 'Chennai',
          state: 'Tamil Nadu',
          pincode: '600001'
        },
        trackingHistory,
        items
      };
    }
    
    return null;
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 via-white to-indigo-50">
      <div className="max-w-4xl mx-auto px-4 py-8">
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
          className="text-center mb-8"
        >
          <Link href="/" className="inline-flex items-center text-blue-600 hover:text-blue-800 mb-4">
            <ArrowLeft className="h-4 w-4 mr-2" />
            Back to Home
          </Link>
          <h1 className="text-3xl font-bold text-gray-900 mb-2">Track Your Order</h1>
          <p className="text-gray-600">Enter your tracking number to get real-time updates</p>
        </motion.div>

        {/* Search Section */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: 0.1 }}
        >
          <Card className="mb-8">
            <CardHeader>
              <CardTitle className="flex items-center">
                <Search className="h-5 w-5 mr-2 text-blue-600" />
                Enter Tracking Number
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="flex gap-3">
                <Input
                  type="text"
                  placeholder="Enter tracking number (e.g., TRK001234)"
                  value={trackingNumber}
                  onChange={(e) => setTrackingNumber(e.target.value.toUpperCase())}
                  onKeyPress={(e) => e.key === 'Enter' && handleTrackOrder()}
                  className="flex-1"
                />
                <Button 
                  onClick={() => handleTrackOrder()}
                  disabled={loading}
                  className="bg-blue-600 hover:bg-blue-700"
                >
                  {loading ? (
                    <motion.div
                      animate={{ rotate: 360 }}
                      transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
                      className="h-4 w-4 border-2 border-white border-t-transparent rounded-full"
                    />
                  ) : (
                    'Track Order'
                  )}
                </Button>
              </div>
                {/* Demo tracking numbers */}
              <div className="mt-4 p-3 bg-blue-50 rounded-lg">
                <p className="text-sm text-blue-800 mb-2">Try these demo tracking numbers:</p>
                <div className="flex flex-wrap gap-2">
                  {['TRK001425', 'TRK001426', 'TRK001427', 'KT123456'].map((demo) => (
                    <button
                      key={demo}
                      onClick={() => {
                        setTrackingNumber(demo);
                        handleTrackOrder(demo);
                      }}
                      className="text-xs bg-blue-600 text-white px-2 py-1 rounded hover:bg-blue-700 transition-colors"
                    >
                      {demo}
                    </button>
                  ))}
                </div>
              </div>
            </CardContent>
          </Card>
        </motion.div>

        {/* Error Message */}
        {error && (
          <motion.div
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            className="mb-6"
          >
            <Card className="border-red-200 bg-red-50">
              <CardContent className="p-4">
                <div className="flex items-center text-red-800">
                  <Package className="h-5 w-5 mr-2" />
                  {error}
                </div>
              </CardContent>
            </Card>
          </motion.div>
        )}

        {/* Tracking Results */}
        {trackingInfo && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.2 }}
            className="space-y-6"
          >
            {/* Order Summary */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center justify-between">
                  <span>Order Details</span>
                  <Badge className={`${getStatusColor(trackingInfo.status)} flex items-center gap-1`}>
                    {getStatusIcon(trackingInfo.status)}
                    {trackingInfo.status.charAt(0).toUpperCase() + trackingInfo.status.slice(1)}
                  </Badge>
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="grid md:grid-cols-2 gap-6">
                  <div className="space-y-4">
                    <div>
                      <p className="text-sm text-gray-600">Order ID</p>
                      <p className="font-mono font-medium">{trackingInfo.id}</p>
                    </div>
                    <div>
                      <p className="text-sm text-gray-600">Tracking Number</p>
                      <p className="font-mono font-medium">{trackingInfo.trackingNumber}</p>
                    </div>
                    <div>
                      <p className="text-sm text-gray-600">Order Date</p>
                      <p className="font-medium">{formatDate(trackingInfo.createdAt)}</p>
                    </div>
                    {trackingInfo.estimatedDelivery && (
                      <div>
                        <p className="text-sm text-gray-600">Estimated Delivery</p>
                        <p className="font-medium text-green-600">
                          {new Date(trackingInfo.estimatedDelivery).toLocaleDateString('en-IN', {
                            year: 'numeric',
                            month: 'long',
                            day: 'numeric'
                          })}
                        </p>
                      </div>
                    )}
                  </div>
                  
                  <div className="space-y-4">
                    <div className="flex items-center">
                      <MapPin className="h-4 w-4 mr-2 text-gray-400" />
                      <div>
                        <p className="text-sm text-gray-600">Delivery Address</p>
                        <p className="font-medium">
                          {trackingInfo.shippingAddress.city}, {trackingInfo.shippingAddress.state} - {trackingInfo.shippingAddress.pincode}
                        </p>
                      </div>
                    </div>
                    
                    <div className="flex items-center">
                      <Phone className="h-4 w-4 mr-2 text-gray-400" />
                      <div>
                        <p className="text-sm text-gray-600">Support</p>
                        <p className="font-medium text-blue-600">+91 98765 43210</p>
                      </div>
                    </div>
                    
                    <div className="flex items-center">
                      <Mail className="h-4 w-4 mr-2 text-gray-400" />
                      <div>
                        <p className="text-sm text-gray-600">Email</p>
                        <p className="font-medium text-blue-600">support@kadalthunai.com</p>
                      </div>
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>

            {/* Order Items */}
            {trackingInfo.items && trackingInfo.items.length > 0 && (
              <Card>
                <CardHeader>
                  <CardTitle>Order Items</CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="space-y-4">
                    {trackingInfo.items.map((item) => (
                      <div key={item.id} className="flex items-center gap-4 p-4 bg-gray-50 rounded-lg">
                        <div className="w-16 h-16 relative rounded-lg overflow-hidden bg-white">
                          <Image
                            src={item.image || '/images/fish-placeholder.jpg'}
                            alt={item.name}
                            fill
                            className="object-cover"
                          />
                        </div>
                        <div className="flex-1">
                          <h4 className="font-medium">{item.name}</h4>
                          <p className="text-sm text-gray-600">Quantity: {item.quantity}</p>
                        </div>
                        <div className="text-right">
                          <p className="font-medium">₹{item.price}</p>
                          <p className="text-sm text-gray-600">Total: ₹{item.price * item.quantity}</p>
                        </div>
                      </div>
                    ))}
                  </div>
                </CardContent>
              </Card>
            )}

            {/* Tracking History */}
            <Card>
              <CardHeader>
                <CardTitle>Tracking History</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-6">
                  {trackingInfo.trackingHistory.map((entry, index) => (
                    <motion.div
                      key={index}
                      initial={{ opacity: 0, x: -20 }}
                      animate={{ opacity: 1, x: 0 }}
                      transition={{ duration: 0.3, delay: index * 0.1 }}
                      className="flex items-start gap-4"
                    >
                      <div className={`flex items-center justify-center w-10 h-10 rounded-full ${
                        index === 0 ? 'bg-blue-100 text-blue-600' : 'bg-gray-100 text-gray-600'
                      }`}>
                        {getStatusIcon(entry.status)}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center justify-between">
                          <h4 className="font-medium text-gray-900">{entry.status}</h4>
                          <span className="text-sm text-gray-500">{formatDate(entry.timestamp)}</span>
                        </div>
                        <p className="text-sm text-gray-600 mt-1">{entry.description}</p>
                      </div>
                    </motion.div>
                  ))}
                </div>
              </CardContent>
            </Card>

            {/* Action Buttons */}
            <Card>
              <CardContent className="p-6">
                <div className="flex flex-col sm:flex-row gap-4">
                  <Button variant="outline" className="flex-1">
                    <Phone className="h-4 w-4 mr-2" />
                    Contact Support
                  </Button>
                  <Button variant="outline" className="flex-1">
                    <Mail className="h-4 w-4 mr-2" />
                    Email Updates
                  </Button>
                  {trackingInfo.status === 'delivered' && (
                    <Button className="flex-1 bg-green-600 hover:bg-green-700">
                      <CheckCircle className="h-4 w-4 mr-2" />
                      Rate Order
                    </Button>
                  )}
                </div>
              </CardContent>
            </Card>
          </motion.div>
        )}

        {/* Help Section */}
        {!trackingInfo && !error && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.3 }}
          >
            <Card>
              <CardHeader>
                <CardTitle>Need Help?</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="grid md:grid-cols-2 gap-6">
                  <div>
                    <h4 className="font-medium mb-2">Where to find your tracking number?</h4>
                    <ul className="text-sm text-gray-600 space-y-1">
                      <li>• Check your order confirmation email</li>
                      <li>• Look in your account's order history</li>
                      <li>• SMS notification sent to your phone</li>
                    </ul>
                  </div>
                  <div>
                    <h4 className="font-medium mb-2">Contact Support</h4>
                    <div className="text-sm text-gray-600 space-y-1">
                      <p>Phone: +91 98765 43210</p>
                      <p>Email: support@kadalthunai.com</p>
                      <p>Hours: 9 AM - 9 PM (7 days a week)</p>
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>
          </motion.div>
        )}
      </div>
    </div>
  );
};

export default TrackOrderPage;
